function riskFactorCell(value,r){const pending=r.primary_status==="APPROVED_PENDING / PRE_OPERATIONAL",missing=value==null||value===""||["Missing Metadata","Data Pending","Not Available","N/A"].includes(value),numeric=Number.isFinite(Number(value)),qualitative=!numeric&&!missing;if(missing)return `<span class="factor-cell missing">Missing Metadata</span>`;if(pending)return `<span class="factor-cell pending">${UI.escapeHtml(String(value))}</span>`;if(numeric){const intensity=Math.min(1,Math.abs(Number(value))),sign=Number(value)<0?"negative":"positive";return `<span class="factor-cell loaded ${sign}" style="--heat:${intensity.toFixed(2)}">${UI.displayNumber(value,{maximumFractionDigits:3})}</span>`}return `<span class="factor-cell proxy">${UI.escapeHtml(String(value))}<small>metadata / expected</small></span>`}
