function riskFactorRows(c){const removed=riskRemovedStrategyIds(c),rows=(c.risk_factor_big_table||[]).filter(r=>!removed.has(r.strategy_id));if(!rows.length)return '<tr><td colspan="18">Data Pending</td></tr>';return rows.map(r=>`<tr class="${r.strategy_id==="COMBINED_PORTFOLIO"?"combined-strategy-row":r.primary_status==="APPROVED_PENDING / PRE_OPERATIONAL"?"pending-row":""}"><td><strong>${r.display_id||"N/A"}</strong><small>${r.strategy_id||"N/A"}</small></td><td><strong>${UI.escapeHtml(r.display_name||"N/A")}</strong><small>${UI.escapeHtml(r.primary_risk_driver||r.economic_logic||"Missing Metadata")}</small></td><td>${r.sleeve_type||"N/A"}</td><td>${UI.StatusBadge({label:r.primary_status||"N/A",tone:r.primary_status==="APPROVED_PENDING / PRE_OPERATIONAL"?"pending":r.primary_status==="Active Composite"?"info":"ok"})}</td><td>${riskFactorValue(r.capital_weight,"percent")}<small>${riskFactorValue(r.nav,"money")}</small></td><td>${riskFactorCell(r.market_exposure,r)}</td><td>${riskFactorCell(r.size_exposure,r)}</td><td>${riskFactorCell(r.value_exposure,r)}</td><td>${riskFactorCell(r.momentum_exposure,r)}</td><td>${riskFactorCell(r.quality_exposure,r)}</td><td>${riskFactorCell(r.volatility_exposure,r)}</td><td>${riskFactorCell(r.liquidity_exposure,r)}</td><td>${riskFactorCell(factorSourceValue(r,["event_filing_exposure","event_filing_risk","event_filing_metadata"]),r)}</td><td>${riskFactorCell(factorSourceValue(r,["microstructure_exposure","microstructure_risk","microstructure_metadata"]),r)}</td><td>${riskFactorCell(factorSourceValue(r,["crowding_concentration_exposure","crowding_concentration_risk","correlation_diversification_note"]),r)}</td><td>${riskFactorCell(factorSourceValue(r,["sector_bias","sector_exposure","sector_metadata"]),r)}</td><td><strong>${r.position_source||"N/A"}</strong><small>${r.legacy_artifact_position_estimate_authoritative===false?"legacy artifact estimate not authoritative":""}</small></td><td>${riskFactorEvidenceCell(r)}</td></tr>`).join("")}
function riskFactorBigTable(c){const removed=riskRemovedStrategyIds(c),rows=(c.risk_factor_big_table||[]).filter(r=>!removed.has(r.strategy_id)),combined=rows.find(r=>r.strategy_id==="COMBINED_PORTFOLIO"),source=rows[0]?.position_source||"committed_shadow_holdings";return `<section class="panel span-12 risk-factor-big-table-panel risk-factor-matrix-v2">${UI.SectionHeader({title:"Risk Factor Matrix v2",meta:`Risk Factor Big Table v1 payload; ${rows.length} current strategy/sleeve rows from operational snapshot; position source ${source}`})}<div class="matrix-legend"><span><i class="missing"></i>Missing Metadata</span><span><i class="pending"></i>Pending / pre-operational</span><span><i class="proxy"></i>Metadata / expected, not quantitative beta</span><span><i class="loaded"></i>Loaded exposure value</span></div>${table(["Strategy / Sleeve","Display Name","Sleeve Type","Primary Status","Weight / Capital","Market","Size","Value","Momentum","Quality","Volatility","Liquidity","Event / Filing","Microstructure","Crowding / Concentration","Sector Bias","Position Source","Evidence / Missing Warning"],riskFactorRows(c),"risk-factor-big-table risk-factor-matrix")}<footer class="monitor-table-footer"><span>Factor cells show Missing Metadata where validated strategy-level factor metadata is absent; missing values are not converted to zero.</span><b>Combined: ${combined?.primary_status||"N/A"} / ${combined?.sleeve_type||"N/A"}</b></footer></section>`}
function marketProxyValue(v,type){if(v==null||v==="")return "Not Available";if(typeof v==="object")return UI.escapeHtml(`${v.priced??"N/A"}/${v.total??"N/A"} ${v.status||""}`);if(["Insufficient History","Data Pending","Not Available","Coverage Missing","Not Applicable","Constituent-Derived Pending"].includes(v))return UI.escapeHtml(v);if(type==="percent")return UI.percent(v,2);if(type==="money")return UI.money(v);if(type==="number")return UI.displayNumber(v,{maximumFractionDigits:3});return UI.escapeHtml(String(v))}
function marketProxyCell(v,type){const numeric=Number.isFinite(Number(v)),pending=["Data Pending","Pending / Pre-operational","Not Applicable"].includes(v),missing=v==null||v===""||["Insufficient History","Not Available","Coverage Missing","Constituent-Derived Pending"].includes(v);if(pending)return `<span class="proxy-cell pending">${marketProxyValue(v,type)}</span>`;if(missing)return `<span class="proxy-cell missing">${marketProxyValue(v,type)}</span>`;if(numeric){const intensity=Math.min(1,Math.abs(Number(v))),sign=Number(v)<0?"negative":"positive";return `<span class="proxy-cell loaded ${sign}" style="--heat:${intensity.toFixed(2)}">${marketProxyValue(v,type)}</span>`}return `<span class="proxy-cell label">${marketProxyValue(v,type)}</span>`}
