function riskFactorHeatmap(c){const rows=riskDecisionRows(c),excluded=riskExcludedRows(c),source=(c.risk_factor_market_proxy_table||[]).length?"risk_factor_market_proxy_table + research_evidence + paper ledgers":"risk_factor_big_table fallback",headers=RISK_HEATMAP_COLUMNS.map(x=>x.label);return `<section class="panel span-12 risk-factor-heatmap-v3">${UI.SectionHeader({title:"Risk Factor Exposure Matrix",meta:`${source}; ${rows.length} active visible rows; ${excluded.length} pending/excluded`})}<div class="risk-heatmap-toolbar"><span>Paper-only shadow-live portfolio. Real funded brokerage capital = $0. No live brokerage fills. Delayed yfinance market-data proxy. Research metrics are historical/backtest evidence. Not a validated Barra / institutional factor model.</span><button type="button" disabled>Refresh status only</button><button type="button" disabled>Export Heatmap</button></div><div class="risk-heatmap-wrap">${table(headers,riskHeatmapRows(c),"risk-heatmap-table")}</div>${riskHeatmapLegend()}<footer class="monitor-table-footer"><span>Default matrix excludes pending research and future institutional layers; missing values remain explicit labels, not zero.</span></footer></section>`}
function fullHeatmapValue(v,type){if(v==null||v==="")return "Not Available";if(typeof v==="object")return UI.escapeHtml(`${v.priced??"N/A"}/${v.total??"N/A"} ${v.status||""}`);if(v==="Missing Metadata")return "Not Loaded";if(["Insufficient History","Data Pending","Not Available","Coverage Missing","Not Applicable","Not Loaded","Constituent-Derived Pending"].includes(v))return UI.escapeHtml(v);if(type==="percent")return UI.percent(v,2);if(type==="money")return UI.money(v);if(type==="number")return UI.displayNumber(v,{maximumFractionDigits:3});return UI.escapeHtml(String(v))}
