function governanceAuthorityRows(c){const cr=c.capital_reconciliation||{},liveAllocation=Number(c.live_capital_percent??0);return [["Initial Shadow Capital",UI.money(cr.initial_shadow_capital||1000000),"Paper-only operating capital","Loaded"],["Real Funded Brokerage Capital","$0","No real funded brokerage capital is loaded","Disabled"],["Brokerage Execution","Disabled","The workstation does not submit brokerage orders","Disabled"],["Live Allocation",UI.percent(liveAllocation,0),"Live allocation remains disabled","Disabled"],["No Live Brokerage Fill","No Live Brokerage Fill","Paper operating records only","Enforced"],["Human Review Required","Required","Admission, allocation, and release decisions require human review","Required"],["Operating Authority Note","The dashboard can display paper operating records and human review states, but it does not authorize or submit live brokerage orders.","Shadow-live paper workstation boundary","Control"]].map(([a,b,detail,status])=>`<tr><td>${a}</td><td>${b}</td><td>${detail}</td><td>${status}</td></tr>`)}
function governanceBlockedRows(c){return [["Factor contribution to risk","validated institutional factor model + covariance history","Not loaded","Blocked","Human review only"],["VaR","validated VaR model + return history","Not loaded","Blocked","Not used"],["Expected Shortfall","validated ES model + return distribution","Not loaded","Blocked","Not used"],["Scenario shock","scenario definitions + exposure model","Not loaded","Blocked","Not used"],["Macro regime","validated macro feed / regime model","Not loaded","Blocked","Human review only"],["External institutional data research","Bloomberg / Morningstar / Factiva / CRSP exports or licensed feeds","Tracked separately","Not represented as loaded","Research only"]].map(([area,input,status,policy,use])=>`<tr><td>${area}</td><td>${input}</td><td>${status}</td><td>${policy}</td><td>${use}</td></tr>`)}
function governanceHandoffRows(c){return [["GitHub",'<a href="https://github.com/linzhongnan0915/global-ai-risk-manager-workstation" target="_blank" rel="noopener">https://github.com/linzhongnan0915/global-ai-risk-manager-workstation</a>',"Source repository reference"],["Hosting",'<a href="https://global-ai-risk-manager-workstation.onrender.com" target="_blank" rel="noopener">https://global-ai-risk-manager-workstation.onrender.com</a>',"Hosted dashboard reference"],["LLM / Agentic Platform","ChatGPT / Codex / Cursor-assisted engineering workflow for implementation planning, testing guidance, release notes, and dashboard QA.","Engineering workflow reference"]].map(([area,reference,use])=>`<tr><td>${area}</td><td>${reference}</td><td>${use}</td></tr>`)}
function libraryPage(){const c=state.contract,rawProvenanceCount=c.execution_provenance?.trade_record_counts?.VERIFIED_SHADOW_EXECUTION??0,active=currentActiveRows(c),pending=currentPendingRows(c);return `<main class="main-stage"><div class="page workflow-page governance-page">${pageTitle("Strategy Library & Governance","Data-bound strategy registry, canonical inputs, transformation lineage, evidence gates, and operating authority.")}<section class="metric-grid governance-metrics">${[["Registry Entities",c.strategies.length,"Loaded strategies[] rows","info"],["Strategy Daily Rows",c.strategy_daily.length,"Loaded strategy_daily[] rows","positive"],["Trade Rows",c.trades.length,"Loaded trades[] rows","warning"],["Holding Rows",c.holdings.length,"Loaded holdings[] rows","info"],["Portfolio Dates",c.portfolio_daily.length,"Loaded portfolio_daily[] dates","positive"],["Top-Level Active",active.length,"Derived from current registry status","positive"],["Pending Candidates",pending.length,"Approved-pending / pre-operational rows","pending"],["Paper Provenance Gate","Pending / Not Fully Verified",`Raw provenance gate count: ${rawProvenanceCount}`,"warning"]].map(x=>UI.MetricCard({label:x[0],value:String(x[1]),detail:x[2],tone:x[3]})).join("")}</section><div class="workflow-grid governance-grid"><section class="panel span-12">${UI.SectionHeader({title:"CANONICAL INPUT INVENTORY",meta:"Loaded artifacts only; missing inputs remain Not loaded"})}${table(["Input Artifact","Current Status","Observed Count","As-of / Effective Date","Downstream Use"],governanceInputRows(c))}</section><section class="panel span-12">${UI.SectionHeader({title:"DATA PROCESSING LINEAGE",meta:"Snapshot-bound processing, derived outputs, and blocked model checks"})}${table(["Processing Step","Input","Work Performed","Output","Status"],governanceLineageRows(c))}</section><section class="panel span-12">${UI.SectionHeader({title:"STRATEGY LIFECYCLE REGISTRY",meta:`${c.strategies.length} canonical strategy rows; ${pending.length} pending / pre-operational rows separated`})}${table(["Display ID","Strategy","Family","Lifecycle","Operational Status","Research Status","Effective Date","Current Sleeve","Proposed Sleeve","Execution Authority","Data State","Next Action"],governanceRegistryRows(c))}</section><section class="panel span-12">${UI.SectionHeader({title:"EVIDENCE GATE MATRIX",meta:"Canonical operating evidence by strategy group"})}${table(["Strategy Group","Canonical Signal","Target Rows","Paper Fill Rows","Position Rows","Verified Provenance","Admission State"],governanceGateRows(c))}</section><section class="panel span-6">${UI.SectionHeader({title:"OPERATING AUTHORITY & EXECUTION CONTROLS",meta:"Shadow-live paper workstation boundary"})}${table(["Constraint","Current Value","Governance meaning","State"],governanceAuthorityRows(c))}</section><section class="panel span-6">${UI.SectionHeader({title:"DATA GAPS & BLOCKED ANALYTICS",meta:"Unsupported analytics remain blocked until validated inputs are loaded"})}${table(["Analytics Area","Required Input","Current Status","Fallback Policy","Decision Use"],governanceBlockedRows(c))}</section><section class="panel span-12">${UI.SectionHeader({title:"PROJECT HANDOFF REFERENCES",meta:"Static project references; not market or accounting data"})}${table(["Reference Area","Reference","Use"],governanceHandoffRows(c))}</section></div></div></main>`}
function reportPage(){const c=state.contract,s=c.portfolio_summary,pending=currentPendingRows(c),rows=c.strategies.slice().sort((a,b)=>Math.abs(b.daily_pnl||0)-Math.abs(a.daily_pnl||0)).map(x=>`<tr><td>${x.display_id}</td><td>${x.ui_name}</td><td class="tone-${UI.toneForNumber(x.daily_pnl)}">${UI.money(x.daily_pnl)}</td><td class="tone-${UI.toneForNumber(x.cumulative_pnl)}">${UI.money(x.cumulative_pnl)}</td><td>${isPendingAdmission(x)?"APPROVED_PENDING / PRE_OPERATIONAL":x.membership_state}</td><td>${x.data_status}</td></tr>`);return `<main class="main-stage"><div class="page workflow-page">${pageTitle("Daily Risk Report / Decision Log",`Report date ${s.as_of_date}`)}${releasePanel()}${secondaryStageNote("Daily report staging status",[["BLOCKED_SAFE","Official ledger promotion is blocked by missing runtime promotion input and required canonical pipeline readiness."],["SEPARATE","Delayed estimates remain separate and are not official ledger records."],["UNCHANGED","NEXT_OPEN_TO_OPEN remains unchanged; no fake official ledger row is represented."]])}${metrics(c)}<div class="workflow-grid"><section class="panel span-7">${UI.SectionHeader({title:"Daily strategy summary",meta:"Sorted by absolute daily P&L"})}${table(["ID","Strategy","Daily P&L","Cumulative P&L","Membership","Data"],rows)}</section><div class="span-5 stack-panels">${alerts(c)}${UI.Panel({title:"Human decision notes",meta:"Operational memo",body:`<div class="memo"><p>Official ledger promotion is blocked by missing runtime promotion input and required canonical pipeline readiness. Delayed estimates remain separate and are not official ledger records.</p><p>Live allocation remains 0% and execution is disabled.</p><p>${pending.length} pending / pre-operational row(s) are not active until canonical signal rows, target rows, paper fill rows, position rows, and verified execution provenance are present.</p><p>Current drawdown, correlation and institutional risk statistics remain unavailable in the canonical bundle.</p></div>`})}</div><div class="span-6">${UI.ChartPanel({title:"Portfolio operating NAV",meta:"Committed observations",canvasId:"reportNavChart"})}</div><div class="span-6">${timeline(c)}</div></div></div></main>`}
function strategyMonitorPage(){const c=state.contract,s=currentStrategyRows(c),cr=c.capital_reconciliation||{},inv=c.strategy_entity_inventory||{},active=currentActiveRows(c),pending=currentPendingRows(c),ordinaryActive=active.filter(x=>x.internal_id!=="COMBINED_PORTFOLIO").length,unavailable=s.filter(x=>!["COMPLETE","DERIVED_COMPLETE"].includes(x.data_state||x.data_status)),u=c.operational_universe||{},cards=[["Current Rows",s.length,"Visible operating rows","info"],["Ordinary Active",inv.ordinary_operational_ledgers??ordinaryActive,"Standalone active ledgers","positive"],["Top-Level Active",active.length,"Derived from current registry","positive"],["Pending",pending.length,pending.length?"Review needed":"No pending candidate","positive"],["Combined",cr.combined_internal_constituents??"N/A","Internal constituents","info"],["Equal Sleeve",UI.percent(cr.top_level_sleeve_weight,2),"Top-level weight","info"],["Data Issues",unavailable.length,"Incomplete current rows","warning"],["Latest Refresh",c.last_successful_refresh?new Date(c.last_successful_refresh).toLocaleTimeString():"N/A",`${freshnessLabel(c)} | held ${u.current_price_covered_ticker_count??"N/A"}/${u.held_ticker_count??"N/A"}`,"info"]];return `<main class="main-stage"><div class="page strategy-monitor-page">${pageTitle("Strategy Monitor",`${active.length} active operating rows from the current registry; ${pending.length} pending / inactive rows separated`) }<section class="metric-grid strategy-monitor-kpis">${cards.map(x=>UI.MetricCard({label:x[0],value:String(x[1]),detail:x[2],tone:x[3]})).join("")}</section>${strategyPanel()}</div></main>`}
function allocationActiveSleeves(c){return currentActiveRows(c)}
function allocationStorageKey(c){return `risk-workstation.paper-allocation.${allocationActiveSleeves(c).map(s=>s.internal_id).join("|")}`}
function allocationPlanStorageKey(c){return `${allocationStorageKey(c)}.planStatus`}
function allocationEqualWeights(c){const sleeves=allocationActiveSleeves(c),w=sleeves.length?1/sleeves.length:0;return Object.fromEntries(sleeves.map(s=>[s.internal_id,w]))}
function allocationReadSaved(c){try{const raw=localStorage.getItem(allocationStorageKey(c));if(!raw)return null;const parsed=JSON.parse(raw),ids=new Set(allocationActiveSleeves(c).map(s=>s.internal_id));if(!parsed||typeof parsed!=="object")return null;for(const id of Object.keys(parsed)){if(!ids.has(id)||!Number.isFinite(Number(parsed[id]))||Number(parsed[id])<0)return null}return Object.fromEntries([...ids].map(id=>[id,Number(parsed[id]??0)]))}catch{return null}}
function allocationDraft(c){if(!state.allocationDraftWeights){state.allocationDraftWeights=allocationReadSaved(c)||allocationEqualWeights(c);try{state.allocationPlanStatus=localStorage.getItem(allocationPlanStorageKey(c))||"Draft / Review"}catch{state.allocationPlanStatus="Draft / Review"}}return state.allocationDraftWeights}
function allocationTargetTotal(weights){return Object.values(weights||{}).reduce((n,v)=>n+Number(v||0),0)}
function allocationShadowCapital(c){return Number(c.portfolio_summary?.nav??c.capital_reconciliation?.initial_shadow_capital??1000000)}
const ALLOCATION_DUST_NOTIONAL=100,ALLOCATION_DUST_DRIFT=0.0001
function allocationPlanRows(c){const weights=allocationDraft(c),capital=allocationShadowCapital(c);return allocationActiveSleeves(c).map(s=>{const currentRaw=s.current_weight??s.sleeve_weight,targetRaw=weights[s.internal_id],current=Number(currentRaw),target=Number(targetRaw),hasData=Number.isFinite(current)&&Number.isFinite(target),currentNotional=hasData?current*capital:null,targetNotional=Number.isFinite(target)?target*capital:null,trade=hasData?targetNotional-currentNotional:null,drift=hasData?target-current:null,material=hasData&&Math.abs(trade)>=ALLOCATION_DUST_NOTIONAL&&Math.abs(drift)>=ALLOCATION_DUST_DRIFT,cost=material?Math.abs(trade)*0.0005:0;return {s,current:hasData?current:null,target:Number.isFinite(target)?target:null,currentNotional,targetNotional,trade,drift,material,cost,hasData}})}
function allocationMaterialRows(c){return allocationPlanRows(c).filter(r=>r.material)}
function allocationDecision(r){if(!r.hasData)return "REVIEW";if(!r.material)return "HOLD";return r.drift>0?"INCREASE":"REDUCE"}
function allocationDecisionTone(action){return action==="INCREASE"?"positive":action==="REDUCE"?"negative":action==="REVIEW"?"warning":"info"}
function allocationPlanValidation(total){const eps=0.0001;if(total>1+eps)return {state:"OVER-ALLOCATED",tone:"negative",ok:false,residual:0,overUnder:total-1,detail:"Normalize to 100% before Save / Generate"};if(total<1-eps)return {state:"RESIDUAL CASH",tone:"warning",ok:true,residual:1-total,overUnder:total-1,detail:"Unallocated cash remains in paper target"};return {state:"READY",tone:"positive",ok:true,residual:0,overUnder:0,detail:"Target allocation equals 100%"}}
function allocationPersistDraft(c){localStorage.setItem(allocationStorageKey(c),JSON.stringify(allocationDraft(c)));localStorage.setItem(allocationPlanStorageKey(c),state.allocationPlanStatus)}
function allocationSetEqual(){state.allocationDraftWeights=allocationEqualWeights(state.contract);state.allocationPlanStatus="Draft / Review";allocationPersistDraft(state.contract);render()}
function allocationNormalize(){const c=state.contract,w=allocationDraft(c),total=allocationTargetTotal(w);if(total<=0){toast("Cannot normalize zero allocation","negative");return}state.allocationDraftWeights=Object.fromEntries(Object.entries(w).map(([id,v])=>[id,Number(v)/total]));state.allocationPlanStatus="Draft / Review";allocationPersistDraft(c);render()}
function allocationSaveTarget(){const total=allocationTargetTotal(allocationDraft(state.contract)),v=allocationPlanValidation(total);if(!v.ok){toast(v.detail,"negative");return}state.allocationPlanStatus=total<0.9999?"Saved Paper Target / Residual Cash":"Saved Paper Target";allocationPersistDraft(state.contract);toast("Paper target saved in browser storage","positive");render()}
function allocationGeneratePlan(){const total=allocationTargetTotal(allocationDraft(state.contract)),v=allocationPlanValidation(total);if(!v.ok){toast(v.detail,"negative");return}state.allocationPlanStatus=allocationMaterialRows(state.contract).length?"Draft / Review":"No Material Paper Rebalance Required";allocationPersistDraft(state.contract);toast(state.allocationPlanStatus,"positive");render()}
function allocationSetPlanStatus(status){state.allocationPlanStatus=status;allocationPersistDraft(state.contract);toast(`Plan status: ${status}`,"positive");render()}
function allocationSyncTargetUi(total){const v=allocationPlanValidation(total);document.querySelector("[data-allocation-total]")?.replaceChildren(document.createTextNode(UI.percent(total,2)));document.querySelector("[data-allocation-residual]")?.replaceChildren(document.createTextNode(UI.percent(v.residual,2)));document.querySelector("[data-allocation-over-under]")?.replaceChildren(document.createTextNode(UI.percent(v.overUnder,2)));document.querySelector("[data-allocation-validation]")?.replaceChildren(document.createTextNode(v.state));document.querySelectorAll('[data-allocation-action="save"],[data-allocation-action="generate"]').forEach(b=>{b.disabled=!v.ok})}
function bindAllocationControls(){document.querySelectorAll("[data-allocation-input]").forEach(input=>input.addEventListener("input",e=>{const id=e.target.dataset.allocationInput,value=Number(e.target.value);if(!state.allocationDraftWeights)allocationDraft(state.contract);state.allocationDraftWeights[id]=Number.isFinite(value)?Math.max(0,value)/100:0;state.allocationPlanStatus="Draft / Review";allocationSyncTargetUi(allocationTargetTotal(state.allocationDraftWeights))}));document.querySelectorAll("[data-allocation-action]").forEach(b=>b.addEventListener("click",()=>{const a=b.dataset.allocationAction;if(a==="equal")allocationSetEqual();if(a==="normalize")allocationNormalize();if(a==="save")allocationSaveTarget();if(a==="generate")allocationGeneratePlan();if(a==="accept")allocationSetPlanStatus("Accepted / Pending Paper Application");if(a==="modify")allocationSetPlanStatus("Draft / Review");if(a==="reject")allocationSetPlanStatus("Rejected")}))}
function allocationControlStrip(c,total,validation){return `<section class="allocation-control-strip"><div><span>Portfolio Mode</span><b>Shadow-Live Paper</b></div><div><span>Target Allocated %</span><b data-allocation-total class="tone-${validation.tone}">${UI.percent(total,2)}</b></div><div><span>Residual Cash %</span><b data-allocation-residual>${UI.percent(validation.residual,2)}</b></div><div><span>Over / Under Allocation %</span><b data-allocation-over-under class="tone-${validation.tone}">${UI.percent(validation.overUnder,2)}</b></div><div><span>Paper Target</span><b>User adjustable</b></div><div><span>Save Method</span><b>browser/session persisted</b></div><div><span>Brokerage Execution</span><b class="tone-warning">Disabled</b></div><div><span>Target Validation</span><b data-allocation-validation class="tone-${validation.tone}">${validation.state}</b></div></section>`}
function allocationDisplayPercent(v){return v==null?"Unavailable":UI.percent(v,2)}
function allocationDisplayMoney(v){return v==null?"Unavailable":UI.money(v)}
function allocationEditableRows(c){return allocationPlanRows(c).map(r=>{const action=allocationDecision(r),tone=allocationDecisionTone(action),tradeText=r.material?UI.money(r.trade):r.hasData?UI.money(0):"Unavailable";return `<tr><td>${r.s.display_id}</td><td><strong>${r.s.ui_name}</strong><small>${r.s.internal_id}</small></td><td>${UI.StatusBadge({label:"ACTIVE PAPER SLEEVE",tone:r.s.internal_id==="COMBINED_PORTFOLIO"?"info":"ok"})}</td><td>${allocationDisplayPercent(r.current)}<small>${allocationDisplayMoney(r.currentNotional)}</small></td><td><input class="allocation-input" type="number" min="0" step="0.01" value="${((r.target??0)*100).toFixed(2)}" data-allocation-input="${UI.escapeHtml(r.s.internal_id)}" aria-label="Target allocation for ${UI.escapeHtml(r.s.ui_name)}"></td><td class="tone-${UI.toneForNumber(r.drift)}">${allocationDisplayPercent(r.drift)}</td><td>${allocationDisplayMoney(r.targetNotional)}</td><td class="tone-${r.material?UI.toneForNumber(r.trade):"info"}">${tradeText}</td><td>${UI.money(r.cost)}</td><td><span class="allocation-action-badge tone-${tone}">${action}</span></td></tr>`}).join("")}
function allocationTradeRows(c){const rows=allocationMaterialRows(c).sort((a,b)=>Math.abs(b.trade)-Math.abs(a.trade));if(!rows.length)return `<tr><td colspan="8"><strong>No material paper rebalance required</strong><small>All sleeve drifts are below ${UI.money(ALLOCATION_DUST_NOTIONAL)} or ${UI.percent(ALLOCATION_DUST_DRIFT,2)}.</small></td></tr>`;return rows.map(({s,trade,cost,target,current})=>`<tr><td>${s.display_id}</td><td><strong>${s.ui_name}</strong><small>${trade>0?"Paper BUY sleeve notional":trade<0?"Paper SELL sleeve notional":"No sleeve trade"}</small></td><td class="tone-${UI.toneForNumber(trade)}">${trade>0?"BUY":trade<0?"SELL":"NO TRADE"}</td><td>${UI.money(Math.abs(trade))}</td><td>${allocationDisplayPercent(current)}</td><td>${allocationDisplayPercent(target)}</td><td>${UI.money(cost)}</td><td>No live order; no official ledger change</td></tr>`).join("")}
function allocationWarnings(c,total,validation){const pending=(c.strategies||[]).filter(s=>!allocationActiveSleeves(c).some(a=>a.internal_id===s.internal_id)),saved=allocationReadSaved(c),material=allocationMaterialRows(c).length;return `<div class="allocation-warning-list"><div><span>Inactive / pending rows</span><b>${pending.length} separated by registry status</b></div><div><span>Target validation</span><b class="tone-${validation.tone}">${validation.detail}</b></div><div><span>Residual cash handling</span><b>${validation.residual>0?`${UI.percent(validation.residual,2)} unallocated cash`:"No residual cash"}</b></div><div><span>Dust threshold</span><b>${UI.money(ALLOCATION_DUST_NOTIONAL)} / ${UI.percent(ALLOCATION_DUST_DRIFT,2)}</b></div><div><span>Material trade rows</span><b>${material?material:"None"}</b></div><div><span>Saved target loaded</span><b>${saved?"Yes":"No; equal-weight default"}</b></div><div><span>Real Funded Brokerage Capital</span><b>$0</b></div><div><span>Official ledger</span><b class="tone-positive">Unchanged</b></div></div>`}
function allocationActionsPanel(validation){return UI.Panel({title:"Paper action center",meta:"No button executes live trades",className:"allocation-action-center",body:`<div class="allocation-buttons"><button data-allocation-action="equal">Reset Equal Weight</button><button data-allocation-action="normalize">Normalize to 100%</button><button data-allocation-action="save" ${validation.ok?"":"disabled"}>Save Paper Target</button><button data-allocation-action="generate" ${validation.ok?"":"disabled"}>Generate Paper Rebalance Plan</button><button class="approve-tile" data-allocation-action="accept">Accept</button><button class="modify-tile" data-allocation-action="modify">Modify</button><button class="reject-tile" data-allocation-action="reject">Reject</button></div><div class="decision-box compact"><strong>${UI.escapeHtml(state.allocationPlanStatus)}</strong><span>${validation.detail}. Paper-only workflow; no official ledger mutation and no brokerage execution.</span><em>Execution authorized: NO</em></div>`})}
function allocationPage(){const c=state.contract,sleeves=allocationActiveSleeves(c),rows=allocationPlanRows(c),materialRows=rows.filter(r=>r.material),total=allocationTargetTotal(allocationDraft(c)),validation=allocationPlanValidation(total),currentAllocated=rows.reduce((n,r)=>n+Number(r.current||0),0),tradeNotional=materialRows.reduce((n,r)=>n+Math.abs(r.trade),0),tradeCost=materialRows.reduce((n,r)=>n+r.cost,0),turnover=materialRows.reduce((n,r)=>n+Math.abs(r.drift),0)/2;return `<main class="main-stage"><div class="page workflow-page allocation-workstation-page">${pageTitle("Allocation & Rebalance",`${sleeves.length} active paper sleeves from current registry; pending / inactive rows are excluded by status`)}${allocationControlStrip(c,total,validation)}<section class="metric-grid allocation-kpis">${[["Current Allocated %",UI.percent(currentAllocated,2),"Sum of active sleeve current weights","info"],["Target Allocated %",UI.percent(total,2),validation.state,validation.tone],["Residual Cash %",UI.percent(validation.residual,2),validation.residual>0?"Unallocated paper cash":"No residual cash",validation.residual>0?"warning":"positive"],["Over / Under Allocation %",UI.percent(validation.overUnder,2),validation.detail,validation.tone],["Active Sleeves",sleeves.length,"Derived from currentActiveRows()","positive"],["Estimated Paper Trade Notional",UI.money(tradeNotional),materialRows.length?"Dust excluded":"No material paper rebalance required",materialRows.length?"warning":"positive"],["Estimated Cost",UI.money(tradeCost),"Dust trades excluded; 5 bps assumption","warning"],["Plan Status",state.allocationPlanStatus,"Paper target review only","info"]].map(x=>UI.MetricCard({label:x[0],value:String(x[1]),detail:x[2],tone:x[3]})).join("")}</section><div class="allocation-layout"><section class="panel allocation-matrix-panel">${UI.SectionHeader({title:"Paper allocation matrix",meta:"Sleeve action uses HOLD / INCREASE / REDUCE / REVIEW; dust ignored"})}${table(["ID","Strategy","State","Current","Target %","Drift","Target Notional","Paper Trade","Est. Cost","Action"],allocationEditableRows(c),"allocation-edit-table")}<footer class="monitor-table-footer"><span>Current allocation is read from available paper allocation / snapshot fields.</span><b>Missing values remain Unavailable; no zero fill unless known.</b><span>Dust threshold: ${UI.money(ALLOCATION_DUST_NOTIONAL)} or ${UI.percent(ALLOCATION_DUST_DRIFT,2)}.</span></footer></section><aside class="allocation-side">${allocationActionsPanel(validation)}${UI.Panel({title:"Warnings / notes",meta:"Semantic safety",body:allocationWarnings(c,total,validation)})}${allocation(c)}</aside><section class="panel allocation-trade-panel">${UI.SectionHeader({title:"Generated paper rebalance plan",meta:`${state.allocationPlanStatus}; material trades only; no official ledger or live broker modification`})}${table(["ID","Strategy","Direction","Paper Notional","Current","Target","Est. Cost","Boundary"],allocationTradeRows(c),"allocation-trade-table")}</section><section class="panel allocation-explain-panel">${UI.SectionHeader({title:"Paper allocation rationale",meta:"Beginner explainable"})}<div class="memo"><p>Default target is equal weight across active top-level sleeves. Edits update target weights only; Normalize rescales them to 100%.</p><p>Paper trade notional = target notional minus current notional. Estimated turnover and cost exclude dust trades below ${UI.money(ALLOCATION_DUST_NOTIONAL)} or ${UI.percent(ALLOCATION_DUST_DRIFT,2)} drift.</p><p>Official Ledger, Paper Performance, Delayed Estimate, and Live Brokerage stay separate. This page is a paper decision tool, not a broker or accounting engine.</p></div></section></div></div></main>`}
function workflowNode(title,status,detail,tone="info"){return `<article class="workflow-map-node tone-${tone}"><strong>${UI.escapeHtml(title)}</strong><b>${UI.escapeHtml(status)}</b><span>${UI.escapeHtml(detail)}</span></article>`}
function workflowLane(title,nodes){return `<section class="panel workflow-lane">${UI.SectionHeader({title,meta:"Secondary audit detail"})}<div class="workflow-map-row">${nodes.map((n,i)=>`${i?'<i class="workflow-map-arrow">-></i>':""}${workflowNode(...n)}`).join("")}</div></section>`}
function workflowDiagramCard(n,title,status,bullets,tone="info"){return `<article class="workflow-command-node tone-${tone}"><span>${String(n).padStart(2,"0")} - ${UI.escapeHtml(title)}</span><strong>${UI.escapeHtml(status)}</strong><ul>${bullets.map(x=>`<li>${UI.escapeHtml(String(x))}</li>`).join("")}</ul></article>`}
function workflowCommandDiagram(c,{active,pending,coverage,schedulerState,manual,poll,refresh}){const paperRows=c.paper_portfolio_daily?.rows?.length||c.portfolio_daily.length,holdings=c.holdings.length,tradeRows=c.trades.length,riskRows=(c.risk_factor_market_proxy_table||[]).length;const cards=[
  [1,"Data Sources",coverage,["delayed yfinance proxy","future boss API ready","no live brokerage data"],"warning"],
  [2,"Strategy Registry",`${active.length} active / ${pending.length} pending`,["active sleeves from registry","pre-operational separated","future active rows auto-join"],"positive"],
  [3,"Shadow Holdings",`${holdings} paper rows`,["committed paper holdings","Real Funded Brokerage Capital: $0","no brokerage capital"],"info"],
  [4,"Refresh Engine",schedulerState,["30-minute scheduler","manual /api/refresh-data","UI polling /api/operational-snapshot"],"info"],
  [5,"Paper Performance",`${paperRows} ledger rows`,["paper ledger","delayed estimate","official ledger separate"],"positive"],
  [6,"Risk / Allocation Controls",`${riskRows} proxy rows`,["risk monitor","paper target weights","rebalance estimate"],"warning"],
  [7,"Dashboard Command Center",`${WORKFLOW_TABS.length} tabs`,["portfolio / strategy / risk","allocation decision support","no official row mutation"],"info"],
  [8,"Output","Human review required",["shadow-live paper workstation","no live fill","decision support only"],"pending"]
];return `<section class="workflow-command-diagram"><header><div><strong>Shadow-Live Paper Command Workflow</strong><span>Snapshot-linked diagram. Counts/statuses are derived from the current registry and operational artifacts.</span></div><em>${refresh}</em></header><div class="workflow-command-grid">${cards.map(x=>workflowDiagramCard(...x)).join("")}</div><div class="workflow-command-output"><strong>Output: Shadow-Live Paper Risk Workstation</strong><span>Official Ledger: Unchanged</span><span>Paper Target: User adjustable</span><span>Save Method: browser/session persisted</span><span>Brokerage Execution: Disabled</span><span>Live Fill: No</span><span>Paper trades loaded: ${tradeRows}</span></div></section>`}
function workflowFrameworkLanes(c,active,pending,g,blockers){const combined=c.strategies.find(s=>s.internal_id==="COMBINED_PORTFOLIO")||{},ordinary=active.filter(s=>s.internal_id!=="COMBINED_PORTFOLIO"),paperTradeRows=c.trades.length,positionRows=c.holdings.length;return `${workflowLane("Strategy Development Workflow",[["Research Idea",`${c.strategies.length} registry rows`,"Historical research stays separate from operations","info"],["Signal Definition",c.strategy_daily.length?"Loaded":"Unavailable","Read from canonical strategy_daily / signal artifacts when present","info"],["Target Construction",c.operational_status?.latest_valid_target_position_date||"Unavailable","Missing target rows stay Pending / Unavailable","warning"],["Backtest Evidence",c.strategies.filter(s=>s.research_evidence||s.research_evidence_available).length,"Research metrics are displayed only when loaded","info"]])}${workflowLane("Shadow-Live Paper Testing Workflow",[["Strategy Registry",`${active.length} active; ${pending.length} pending`,"Rows derive from current registry status","positive"],["Paper Execution Record",paperTradeRows?`${paperTradeRows} rows`:"Unavailable","Paper-only trade records; no brokerage execution","warning"],["Position Ledger",positionRows?`${positionRows} rows`:"Unavailable","Paper holdings / positions only","info"],["Human Approval",pending.length?`${pending.length} pending`:"Required for changes","No automatic admission or live execution","pending"]])}${workflowLane("Strategy Admission Gate",[["Candidate Registry",pending.length?`${pending.length} pending`:"No pending active admission","Approved-pending / pre-operational rows are separated","pending"],["Evidence Gate",g.status||"Evidence-gated",blockers[0]||"Pending evidence","warning"],["Human Approval","Required","Admission remains review-gated","pending"],["Operating Set",`${active.length} active`,"Only active rows enter allocation","positive"]])}${workflowLane("Combined Strategy Operating Workflow",[["Ordinary Constituents",`${ordinary.length} active ordinary rows`,"Derived from current active registry","info"],["Combined Strategy Ledger",combined.data_status||"Unavailable","Derived from ordinary strategy net returns","positive"],["Combined Paper Fills","None","No separate Combined paper fills; no cost double count","warning"]])}${workflowLane("Risk Review Workflow",[["Risk Model Inputs",c.available_factor_outputs?"Loaded":"Unavailable","Institutional factor/VaR/ES inputs must be validated before rendering","warning"],["Market Proxy",c.risk_factor_market_proxy_table?.length||0,"Proxy fields stay labeled as proxy","info"],["Review Decision","Human review","Missing data remains Unavailable / Pending / Proxy / Limited history","pending"]])}${workflowLane("Local-First Release Workflow",[["Local Snapshot",c.snapshot_id||c.snapshot_version||"Loaded","Dashboard reads shared local snapshot state","positive"],["Browser Verification","Required","Release checks must pass before handoff","info"],["Deployment Handoff","Project Handoff References","Static project references are not market/accounting data","info"]])}`}
function workflowTestingPage(){const c=state.contract,active=allocationActiveSleeves(c),pending=currentPendingRows(c),intr=c.intraday_estimate||{},u=c.operational_universe||{},promo=promotionReadiness(c),covered=u.current_price_covered_ticker_count??intr.covered_tickers,total=u.held_ticker_count??intr.total_tickers,coverage=covered!=null&&total!=null?`${covered}/${total}`:"Unavailable",refresh=refreshStatusLabel(c),schedulerState=c.intraday_scheduler_enabled===false?"Configured / currently disabled":"Enabled",manual="/api/refresh-data",poll="/api/operational-snapshot",g=c.wq_admission_gate||{},blockers=(g.blockers&&g.blockers.length?g.blockers:["Pending evidence"]);const kpis=[["Portfolio Mode","Shadow-Live Paper","Paper operation boundary","positive"],["Real Funded Capital","$0","No brokerage funding","warning"],["Brokerage Execution","Disabled","Live Fill = No","warning"],["Active Sleeves",active.length,"current active top-level sleeves","positive"],["Pending Candidates",pending.length,"Excluded from active allocation","pending"],["Delayed Coverage",coverage,"yfinance proxy when loaded","info"],["Manual Refresh",manual,"POST endpoint","info"],["UI Polling",poll,"Lightweight snapshot polling","info"]];return `<main class="main-stage"><div class="page workflow-page workflow-map-page">${workflowTestingTitle()}${workflowCommandDiagram(c,{active,pending,coverage,schedulerState,manual,poll,refresh})}<details class="workflow-secondary-detail"><summary>Detailed workflow audit sections</summary><section class="metric-grid workflow-testing-metrics">${kpis.map(x=>UI.MetricCard({label:x[0],value:String(x[1]),detail:x[2],tone:x[3]})).join("")}</section><div class="workflow-map-layout"><section class="panel workflow-boundary-panel">${UI.SectionHeader({title:"Operating boundary",meta:"Clear separation of official, paper, delayed estimate, and live brokerage"})}<div class="workflow-boundary-grid">${workflowNode("Official Ledger",c.portfolio_daily.length?"Loaded":"Unavailable",`${c.portfolio_daily.length} portfolio_daily rows; not changed by refresh or allocation UI`,"positive")}${workflowNode("Paper Performance",c.paper_portfolio_daily?.rows?.length?"Loaded / Runtime":"Limited history","Separate paper daily artifact when delayed refresh writes paper-only estimates","info")}${workflowNode("Delayed Estimate",intr.estimated_nav!=null?refresh:"Unavailable",`Provider ${intr.provider||"yfinance proxy"}; coverage ${coverage}`,"warning")}${workflowNode("Live Brokerage","Disabled","Real funded brokerage capital = $0; Live Fill = No","warning")}</div></section>${workflowLane("Refresh and dashboard flow",[["Committed Shadow Holdings",c.holdings.length?`${c.holdings.length} rows`:"Unavailable","Source positions for delayed estimate","positive"],["Delayed yfinance proxy now / boss API later",intr.provider||"Proxy / Pending",`Coverage ${coverage}; not official live market data`,"warning"],["Auto Delayed Refresh","30-minute scheduler refresh",`${schedulerState}; minimum 30-minute background cadence`,"info"],["Manual Refresh",manual,"User-triggered delayed refresh endpoint","info"],["Operational Snapshot",poll,`Snapshot ${c.snapshot_id||c.snapshot_version||"loaded"}`,"positive"],["Dashboard Tabs",`${WORKFLOW_TABS.length} tabs`,`Current page uses shared snapshot state`,"positive"]])}${workflowLane("Strategy admission flow",[["Research Registry",`${c.strategies.length} strategy rows`,"Historical research stays separate from operations","info"],["Evidence Gate",g.status||"Evidence-gated",blockers[0]||"Pending evidence","warning"],["Human Approval",pending.length?`${pending.length} pending`:"No pending active admission","No automatic admission","pending"],["Current Operating Set",`${active.length} active sleeves`,"Only active/current rows enter allocation","positive"]])}${workflowLane("Paper rebalance flow",[["Active Sleeves",`${active.length} loaded`,"Read from current registry / snapshot","positive"],["Editable Paper Targets","localStorage","Browser/session persisted paper target weights","info"],["Paper Rebalance Plan","5 bps cost","Notional drift and estimated paper transaction cost","warning"],["Accept / Modify / Reject","Review status only","No live trades; no official ledger modification","pending"]])}${workflowFrameworkLanes(c,active,pending,g,blockers)}<section class="panel workflow-review-panel">${UI.SectionHeader({title:"Release and safety controls",meta:"Boss-presentable semantics"})}<div class="workflow-warning-grid"><div><span>Official promotion readiness</span><b>${promo.readiness_state||"Unavailable"}</b></div><div><span>Scheduler refresh</span><b>30-minute scheduler refresh</b></div><div><span>Scheduler state</span><b>${schedulerState}</b></div><div><span>Manual refresh endpoint</span><b>${manual}</b></div><div><span>UI polling endpoint</span><b>${poll}</b></div><div><span>Pending / inactive rows</span><b>${pending.length} separated by current status</b></div><div><span>Live brokerage fill</span><b class="tone-warning">Disabled / Not present</b></div><div><span>Missing-data policy</span><b>Unavailable / Pending / Proxy / Limited history</b></div></div><div class="blocker-list">${blockers.slice(0,6).map(x=>`<div><span>${UI.escapeHtml(x)}</span><b>REVIEW</b></div>`).join("")}</div></section></div></details></div></main>`}
function allocationAppliedTarget(c){return c.paper_rebalance?.current_paper_target||null}
function allocationAppliedWeights(c){return allocationAppliedTarget(c)?.weights||{}}
function allocationLatestPlan(c){return state.paperRebalancePlan||c.paper_rebalance?.latest_plan||null}
function allocationLatestCost(c){return c.paper_rebalance?.latest_cost_record||null}
function allocationCurrentWeight(c,s){const applied=allocationAppliedWeights(c),v=applied?.[s.internal_id];if(v!=null&&Number.isFinite(Number(v)))return Number(v);const raw=s.current_weight??s.sleeve_weight;return Number.isFinite(Number(raw))?Number(raw):null}
function allocationDraft(c){if(!state.allocationDraftWeights){const applied=allocationAppliedWeights(c),saved=allocationReadSaved(c),equal=allocationEqualWeights(c);state.allocationDraftWeights=saved||Object.fromEntries(allocationActiveSleeves(c).map(s=>[s.internal_id,Number(applied[s.internal_id]??equal[s.internal_id])]));try{state.allocationPlanStatus=localStorage.getItem(allocationPlanStorageKey(c))||c.paper_rebalance?.latest_plan?.applied_status||"Draft / Review"}catch{state.allocationPlanStatus=c.paper_rebalance?.latest_plan?.applied_status||"Draft / Review"}}return state.allocationDraftWeights}
function allocationReason(r){if(!r.hasData)return "Data incomplete / review required";if(!r.material){if(Math.abs(r.drift||0)<ALLOCATION_DUST_DRIFT)return "Equal-weight maintained";return "Dust trade ignored"}if(r.drift>0)return "Increase toward target";if(r.drift<0)return "Reduce overweight sleeve";return "Equal-weight maintained"}
function allocationPlanRows(c){const weights=allocationDraft(c),capital=allocationShadowCapital(c);return allocationActiveSleeves(c).map(s=>{const current=allocationCurrentWeight(c,s),targetRaw=weights[s.internal_id],target=Number(targetRaw),hasData=Number.isFinite(current)&&Number.isFinite(target),currentNotional=Number.isFinite(current)?current*capital:null,targetNotional=Number.isFinite(target)?target*capital:null,trade=hasData?targetNotional-currentNotional:null,drift=hasData?target-current:null,material=hasData&&Math.abs(trade)>=ALLOCATION_DUST_NOTIONAL&&Math.abs(drift)>=ALLOCATION_DUST_DRIFT,cost=material?Math.abs(trade)*0.0005:0,action=!hasData?"REVIEW":!material?"HOLD":drift>0?"INCREASE":"REDUCE";return {s,current:hasData?current:null,target:Number.isFinite(target)?target:null,currentNotional,targetNotional,trade,drift,material,cost,hasData,action,reason:null}}).map(r=>({...r,reason:allocationReason(r)}))}
function allocationHasReview(c){return allocationPlanRows(c).some(r=>allocationDecision(r)==="REVIEW")}
function allocationPersistDraft(c){localStorage.setItem(allocationStorageKey(c),JSON.stringify(allocationDraft(c)));localStorage.setItem(allocationPlanStorageKey(c),state.allocationPlanStatus)}
function allocationSetEqual(){state.allocationDraftWeights=allocationEqualWeights(state.contract);state.allocationPlanStatus="Draft / Review";allocationPersistDraft(state.contract);render()}
function allocationNormalize(){const c=state.contract,w=allocationDraft(c),total=allocationTargetTotal(w);if(total<=0){toast("Cannot normalize zero allocation","negative");return}state.allocationDraftWeights=Object.fromEntries(Object.entries(w).map(([id,v])=>[id,Number(v)/total]));state.allocationPlanStatus="Draft / Review";allocationPersistDraft(c);render()}
function allocationSaveTarget(){const total=allocationTargetTotal(allocationDraft(state.contract)),v=allocationPlanValidation(total);if(!v.ok){toast(v.detail,"negative");return}state.allocationPlanStatus=total<0.9999?"Saved Draft Target / Residual Paper Cash":"Saved Draft Target";allocationPersistDraft(state.contract);toast("Draft paper target saved locally; generate plan to persist project artifact","positive");render()}
async function allocationRefreshFromResponse(result){if(result.snapshot){state.contract=result.snapshot;enrich(state.contract)}else{await loadSnapshot()}state.paperRebalancePlan=result.plan||result.paper_rebalance?.latest_plan||state.contract.paper_rebalance?.latest_plan||state.paperRebalancePlan;state.allocationPlanStatus=state.paperRebalancePlan?.applied_status||state.paperRebalancePlan?.status||state.allocationPlanStatus;state.allocationDraftWeights=null}
async function allocationApi(path,body){const r=await fetch(path,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(body||{})}),result=await r.json();if(!r.ok)throw new Error(result.error||"Paper rebalance request failed");await allocationRefreshFromResponse(result);return result}
async function allocationGeneratePlan(){const total=allocationTargetTotal(allocationDraft(state.contract)),v=allocationPlanValidation(total);if(!v.ok){toast(v.detail,"negative");return}try{state.allocationBusy=true;render();const result=await allocationApi("/api/paper-rebalance/plan",{target_weights:allocationDraft(state.contract)});toast(result.plan?.paper_trade_notional_total>0?"Paper rebalance plan generated":"No material paper rebalance required","positive")}catch(e){toast(e.message,"negative")}finally{state.allocationBusy=false;render()}}
async function allocationAcceptPlan(){const c=state.contract,plan=allocationLatestPlan(c),total=allocationTargetTotal(allocationDraft(c)),v=allocationPlanValidation(total);if(!v.ok||allocationHasReview(c)){toast(!v.ok?v.detail:"Review rows block accept/apply","negative");return}if(!plan?.plan_id){toast("Generate a project paper plan first","warning");return}try{state.allocationBusy=true;render();await allocationApi("/api/paper-rebalance/accept",{plan_id:plan.plan_id});toast("Plan accepted; pending next paper allocation application","positive")}catch(e){toast(e.message,"negative")}finally{state.allocationBusy=false;render()}}
async function allocationApplyPlan(){const c=state.contract,plan=allocationLatestPlan(c),total=allocationTargetTotal(allocationDraft(c)),v=allocationPlanValidation(total);if(!v.ok||allocationHasReview(c)){toast(!v.ok?v.detail:"Review rows block accept/apply","negative");return}if(!plan?.plan_id){toast("Generate and accept a project paper plan first","warning");return}try{state.allocationBusy=true;render();await allocationApi("/api/paper-rebalance/apply",{plan_id:plan.plan_id});toast("Applied as next paper allocation baseline; no live fill and no official ledger mutation","positive")}catch(e){toast(e.message,"negative")}finally{state.allocationBusy=false;render()}}
async function allocationRejectPlan(){const plan=allocationLatestPlan(state.contract);if(!plan?.plan_id){state.allocationPlanStatus="Rejected";allocationPersistDraft(state.contract);render();return}try{state.allocationBusy=true;render();await allocationApi("/api/paper-rebalance/reject",{plan_id:plan.plan_id});toast("Paper plan rejected","positive")}catch(e){toast(e.message,"negative")}finally{state.allocationBusy=false;render()}}
function allocationSyncTargetUi(total){const v=allocationPlanValidation(total);document.querySelector("[data-allocation-total]")?.replaceChildren(document.createTextNode(UI.percent(total,2)));document.querySelector("[data-allocation-residual]")?.replaceChildren(document.createTextNode(UI.percent(v.residual,2)));document.querySelector("[data-allocation-over-under]")?.replaceChildren(document.createTextNode(UI.percent(v.overUnder,2)));document.querySelector("[data-allocation-validation]")?.replaceChildren(document.createTextNode(v.state));document.querySelectorAll('[data-allocation-action="save"],[data-allocation-action="generate"]').forEach(b=>{b.disabled=!v.ok});document.querySelectorAll('[data-allocation-action="accept"],[data-allocation-action="apply"]').forEach(b=>{b.disabled=!v.ok||allocationHasReview(state.contract)})}
function bindAllocationControls(){document.querySelectorAll("[data-allocation-input]").forEach(input=>input.addEventListener("input",e=>{const id=e.target.dataset.allocationInput,value=Number(e.target.value);if(!state.allocationDraftWeights)allocationDraft(state.contract);state.allocationDraftWeights[id]=Number.isFinite(value)?Math.max(0,value)/100:0;state.allocationPlanStatus="Draft / Review";allocationSyncTargetUi(allocationTargetTotal(state.allocationDraftWeights))}));document.querySelectorAll("[data-allocation-action]").forEach(b=>b.addEventListener("click",()=>{const a=b.dataset.allocationAction;if(a==="equal")allocationSetEqual();if(a==="normalize")allocationNormalize();if(a==="save")allocationSaveTarget();if(a==="generate")allocationGeneratePlan();if(a==="accept")allocationAcceptPlan();if(a==="apply")allocationApplyPlan();if(a==="modify"){state.allocationPlanStatus="Draft / Review";allocationPersistDraft(state.contract);render()}if(a==="reject")allocationRejectPlan()}))}
function allocationControlStrip(c,total,validation){const applied=allocationAppliedTarget(c),plan=allocationLatestPlan(c),cost=allocationLatestCost(c);return `<section class="allocation-control-strip allocation-control-strip-v2"><div><span>Current Applied Paper Target</span><b>${applied?.applied_at?chartDateLabel(applied.applied_at.slice(0,10)):"Snapshot baseline"}</b></div><div><span>Draft Target</span><b data-allocation-total class="tone-${validation.tone}">${UI.percent(total,2)}</b></div><div><span>Residual Cash %</span><b data-allocation-residual>${UI.percent(validation.residual,2)}</b></div><div><span>Plan Status</span><b>${UI.escapeHtml(plan?.applied_status||state.allocationPlanStatus)}</b></div><div><span>Intended Effective Date</span><b>${plan?.intended_effective_date||applied?.intended_effective_date||"Pending plan"}</b></div><div><span>Paper Transaction Cost</span><b>${UI.money(plan?.paper_transaction_cost_total??cost?.paper_transaction_cost_total??0)}</b></div><div><span>Official Ledger</span><b class="tone-positive">Unchanged</b></div><div><span>Live Brokerage Fill</span><b class="tone-warning">No</b></div><div><span>Target Validation</span><b data-allocation-validation class="tone-${validation.tone}">${validation.state}</b></div></section>`}
function allocationDecisionRows(c){const rows=allocationPlanRows(c);return `<div class="allocation-decision-grid" role="table"><div class="allocation-decision-header" role="row"><span>Strategy</span><span>State</span><span>Current %</span><span>Target %</span><span>&Delta; Weight</span><span>Current / Target $</span><span>Paper Trade $</span><span>Action</span><span>Reason / Rationale</span></div><div class="allocation-decision-body">${rows.map(r=>{const action=allocationDecision(r),tone=allocationDecisionTone(action),tradeText=r.material?UI.money(r.trade):r.hasData?UI.money(0):"Unavailable";return `<div class="allocation-decision-row" role="row"><div><strong>${UI.escapeHtml(r.s.ui_name||r.s.display_name||r.s.internal_id)}</strong><small>${UI.escapeHtml(r.s.display_id||r.s.internal_id)}</small></div><span>${UI.escapeHtml((r.s.membership_state||"Unavailable").replaceAll("_"," "))}</span><span>${allocationDisplayPercent(r.current)}</span><label><input class="allocation-input" type="number" min="0" step="0.01" value="${((r.target??0)*100).toFixed(2)}" data-allocation-input="${UI.escapeHtml(r.s.internal_id)}" aria-label="Target allocation for ${UI.escapeHtml(r.s.ui_name||r.s.internal_id)}"><em>%</em></label><span class="tone-${UI.toneForNumber(r.drift)}">${allocationDisplayPercent(r.drift)}</span><span><b>${allocationDisplayMoney(r.currentNotional)}</b><small>${allocationDisplayMoney(r.targetNotional)}</small></span><span class="tone-${r.material?UI.toneForNumber(r.trade):"info"}">${tradeText}</span><span><i class="allocation-action-badge tone-${tone}">${action}</i></span><span class="allocation-reason">${UI.escapeHtml(r.reason)}</span></div>`}).join("")}</div></div>`}
function allocationTradeRows(c){const plan=allocationLatestPlan(c),lineItems=plan?.line_items||[],rows=lineItems.length?lineItems.filter(r=>["INCREASE","REDUCE"].includes(r.action)):allocationMaterialRows(c).map(r=>({strategy_id:r.s.display_id,strategy_name:r.s.ui_name,action:r.trade>0?"INCREASE":"REDUCE",paper_trade_notional:r.trade,current_weight:r.current,target_weight:r.target,estimated_transaction_cost:r.cost,reason:r.reason}));if(!rows.length)return `<tr><td colspan="8"><strong>No material paper rebalance required.</strong><small>All sleeve drifts are below ${UI.money(ALLOCATION_DUST_NOTIONAL)} or ${UI.percent(ALLOCATION_DUST_DRIFT,2)}.</small></td></tr>`;return rows.map(r=>`<tr><td>${UI.escapeHtml(r.strategy_id||"N/A")}</td><td><strong>${UI.escapeHtml(r.strategy_name||"Unavailable")}</strong><small>${UI.escapeHtml(r.reason||"Paper-only rebalance line")}</small></td><td class="tone-${r.action==="INCREASE"?"positive":"negative"}">${r.action}</td><td>${allocationDisplayMoney(Math.abs(Number(r.paper_trade_notional||0)))}</td><td>${allocationDisplayPercent(r.current_weight)}</td><td>${allocationDisplayPercent(r.target_weight)}</td><td>${UI.money(r.estimated_transaction_cost||0)}</td><td>No live order; official ledger unchanged</td></tr>`).join("")}
function allocationWarnings(c,total,validation){const pending=(c.strategies||[]).filter(s=>!allocationActiveSleeves(c).some(a=>a.internal_id===s.internal_id)),saved=allocationReadSaved(c),material=allocationMaterialRows(c).length,review=allocationHasReview(c),plan=allocationLatestPlan(c);return `<div class="allocation-warning-list"><div><span>Validation</span><b class="tone-${validation.tone}">${validation.detail}</b></div><div><span>Save allowed</span><b>${validation.ok?"Yes":"Blocked"}</b></div><div><span>Generate allowed</span><b>${validation.ok?"Yes":"Blocked"}</b></div><div><span>Accept / Apply</span><b>${validation.ok&&!review?"Allowed after plan":"Blocked if over-allocated or REVIEW"}</b></div><div><span>Residual cash handling</span><b>${validation.residual>0?`${UI.percent(validation.residual,2)} retained as paper cash`:"No residual cash"}</b></div><div><span>Dust threshold</span><b>${UI.money(ALLOCATION_DUST_NOTIONAL)} / ${UI.percent(ALLOCATION_DUST_DRIFT,2)}</b></div><div><span>Pending / inactive excluded</span><b>${pending.length}</b></div><div><span>Project artifact plan</span><b>${plan?.plan_id||"Pending generation"}</b></div><div><span>Official ledger unchanged</span><b>Yes</b></div><div><span>Live trading disabled</span><b>No live brokerage fill</b></div></div>`}
function allocationActionsPanel(validation){const c=state.contract,review=allocationHasReview(c),plan=allocationLatestPlan(c),disableCore=!validation.ok||state.allocationBusy,disableApply=disableCore||review||!plan?.plan_id;return UI.Panel({title:"Paper Action Center",meta:"Project artifact persistence; no live trades",className:"allocation-action-center",body:`<div class="allocation-buttons"><button data-allocation-action="equal">Reset Equal Weight</button><button data-allocation-action="normalize">Normalize to 100%</button><button data-allocation-action="save" ${validation.ok?"":"disabled"}>Save Paper Target</button><button data-allocation-action="generate" ${validation.ok&&!state.allocationBusy?"":"disabled"}>Generate Paper Rebalance Plan</button><button class="approve-tile" data-allocation-action="accept" ${disableApply?"disabled":""}>Accept</button><button class="modify-tile" data-allocation-action="modify">Modify</button><button class="approve-tile" data-allocation-action="apply" ${disableApply?"disabled":""}>Apply Paper Rebalance</button><button class="reject-tile" data-allocation-action="reject">Reject</button></div><div class="decision-box compact"><strong>${UI.escapeHtml(plan?.applied_status||state.allocationPlanStatus)}</strong><span>${validation.detail}. ${review?"Review rows must be resolved before accept/apply.":"Paper-only workflow ready for human review."}</span><em>Execution authorized: NO | Brokerage fill: NO | Official ledger mutation: NO</em></div>`})}
function allocationMembershipSummary(c){const active=allocationActiveSleeves(c),pending=(c.strategies||[]).length-active.length;return UI.Panel({title:"Current Membership / Allocation Summary",meta:"Derived from registry and paper target artifact",body:`<div class="allocation-warning-list"><div><span>Active sleeve count</span><b>${active.length}</b></div><div><span>Pending / inactive excluded</span><b>${pending}</b></div><div><span>Current baseline source</span><b>${allocationAppliedTarget(c)?"Applied paper target":"Snapshot weights"}</b></div><div><span>Last applied paper rebalance</span><b>${allocationAppliedTarget(c)?.applied_at?.slice(0,10)||"Unavailable"}</b></div></div>`})}
function allocationPage(){const c=state.contract,sleeves=allocationActiveSleeves(c),rows=allocationPlanRows(c),materialRows=rows.filter(r=>r.material),total=allocationTargetTotal(allocationDraft(c)),validation=allocationPlanValidation(total),currentAllocated=rows.reduce((n,r)=>n+Number(r.current||0),0),tradeNotional=materialRows.reduce((n,r)=>n+Math.abs(r.trade),0),tradeCost=materialRows.reduce((n,r)=>n+r.cost,0),plan=allocationLatestPlan(c);return `<main class="main-stage"><div class="page workflow-page allocation-workstation-page">${pageTitle("Allocation & Rebalance",`${sleeves.length} active paper sleeves from current registry; future ACTIVE rows auto-appear from the shared snapshot`) }${allocationControlStrip(c,total,validation)}<section class="metric-grid allocation-kpis allocation-kpis-v2">${[["Current Allocated %",UI.percent(currentAllocated,2),allocationAppliedTarget(c)?"Applied paper target baseline":"Snapshot baseline","info"],["Target Allocated %",UI.percent(total,2),validation.state,validation.tone],["Residual Cash %",UI.percent(validation.residual,2),validation.residual>0?"Retained as residual paper cash":"No residual cash",validation.residual>0?"warning":"positive"],["Over / Under Allocation %",UI.percent(validation.overUnder,2),validation.detail,validation.tone],["Active Sleeves",sleeves.length,"Derived from current registry","positive"],["Estimated Paper Trade Notional",UI.money(tradeNotional),materialRows.length?"Dust excluded":"No material paper rebalance required",materialRows.length?"warning":"positive"],["Estimated Cost",UI.money(tradeCost),"5 bps buy / 5 bps sell","warning"],["Plan Status",plan?.applied_status||state.allocationPlanStatus,"Paper-only lifecycle","info"],["Target Validation",validation.state,validation.detail,validation.tone]].map(x=>UI.MetricCard({label:x[0],value:String(x[1]),detail:x[2],tone:x[3]})).join("")}</section><div class="allocation-layout allocation-layout-v2"><section class="panel allocation-matrix-panel">${UI.SectionHeader({title:"Paper Allocation Decision Center / Rebalance Recommendation Matrix",meta:"Action and Reason are visible by default; rows are generated from active paper sleeves"})}${allocationDecisionRows(c)}<footer class="monitor-table-footer"><span>Current baseline precedence: applied paper target artifact, then snapshot current/sleeve weight.</span><b>Missing values remain Unavailable; REVIEW blocks accept/apply.</b><span>Dust threshold: ${UI.money(ALLOCATION_DUST_NOTIONAL)} or ${UI.percent(ALLOCATION_DUST_DRIFT,2)}.</span></footer></section><aside class="allocation-side">${allocationActionsPanel(validation)}${UI.Panel({title:"Validation / Warnings",meta:"Paper-only safety checks",body:allocationWarnings(c,total,validation)})}${allocationMembershipSummary(c)}</aside><section class="panel allocation-trade-panel">${UI.SectionHeader({title:"Generated Paper Rebalance Plan",meta:`${plan?.plan_id||"Pending generation"}; ${plan?.intended_effective_date?`effective ${plan.intended_effective_date}`:"intended effective date set on generate"}`})}${table(["ID","Strategy","Action","Paper Notional","Current","Target","Est. Cost","Boundary"],allocationTradeRows(c),"allocation-trade-table")}</section><section class="panel allocation-explain-panel">${UI.SectionHeader({title:"Allocation Rationale / Summary",meta:"Paper-only lifecycle v1"})}<div class="memo"><p>Draft targets can be edited here. Generate persists a project paper rebalance plan under data/paper_rebalance; Accept marks it pending paper application; Apply makes it the next paper allocation baseline and records paper transaction cost.</p><p>Official Ledger: Unchanged. Brokerage Execution: Disabled. Live Brokerage Fill: No. No broker fills or official accounting rows are created.</p><p>${materialRows.length?"Material paper trades are listed below after dust filtering.":"No material paper rebalance required."}</p></div></section></div></div></main>`}
function workflowCommandDiagram(c,{active,pending,coverage,schedulerState,manual,poll,refresh}){const paperRows=(c.paper_performance_daily||[]).length,latestPaper=c.paper_performance_daily_metadata?.latest_date||latestPaperPerformanceDate(c)||"Limited history",holdings=c.holdings.length,delayedCoverage=coverage||"Unavailable",plan=c.paper_rebalance?.latest_plan,applied=c.paper_rebalance?.current_paper_target,dashTabs=Array.isArray(WORKFLOW_TABS)?WORKFLOW_TABS.length:"Unavailable";const cards=[
  [1,"Strategy Registry",`${active.length} active / ${pending.length} pending`,["Active sleeves from registry","Pending/inactive excluded","Future ACTIVE rows auto-join"],"positive"],
  [2,"Data & Proxy Layer",delayedCoverage,["Official ledger separate","Delayed estimate labeled proxy","Missing data stays Unavailable"],"warning"],
  [3,"Shadow Holdings",`${holdings} rows`,["Paper holdings artifact","Real funded capital: $0","No broker execution"],"info"],
  [4,"Refresh Engine",schedulerState,["Scheduler/config status from snapshot",`Manual ${manual}`,"Snapshot polling remains read-only"],"info"],
  [5,"Paper Performance",paperRows?`${paperRows} rows / ${latestPaper}`:"Limited history",["Paper performance separate","No fake official close","Delayed estimates separated"],"positive"],
  [6,"Risk / Allocation Controls",plan?.applied_status||"Draft / Review",["Paper target lifecycle","5 bps cost assumption","Apply only to paper baseline"],"warning"],
  [7,"Dashboard Command Center",`${dashTabs} tabs`,["Shared operational snapshot","Decision support only","No official ledger mutation"],"info"],
  [8,"PM Action Output",applied?"Applied paper target":"Human review required",["Accept / Modify / Reject","Apply as next paper allocation","No live fill"],"pending"]
];return `<section class="workflow-command-diagram"><header><div><strong>Shadow-Live Paper PM Command Workflow</strong><span>Dynamic paper strategy workflow for research admission, shadow holdings, delayed estimates, paper allocation, and dashboard monitoring.</span></div><em>${refresh}</em></header><div class="workflow-command-grid">${cards.map(x=>workflowDiagramCard(...x)).join("")}</div><div class="workflow-command-output"><strong>Output: Shadow-Live Paper Risk Workstation</strong><span>Official Ledger: separate</span><span>Paper Performance: separate</span><span>Delayed Estimate: separate</span><span>Brokerage Execution: disabled</span><span>Live Fill: no</span><span>Human Review: required</span></div></section>`}
function currentPage(){return {"Portfolio Command Center":page,"Strategy Monitor":strategyMonitorPage,"Allocation & Rebalance":allocationPage,"Risk Factors & Exposure":riskPageV1,"Correlation & Diversification":correlationPage,"Workflow & Shadow-Live Testing":workflowTestingPage,"Backtesting & Research Lab":researchPage,"Strategy Library & Governance":libraryPage,"Daily Risk Report":reportPage}[state.selectedPage]()}
function render(){document.getElementById("app").innerHTML=`${topBar(state.contract)}${workflow()}<div class="shell-body">${rail(state.contract)}${currentPage()}</div>${UI.DetailDrawer()}<div id="commandToast" class="command-toast" role="status"></div>`;bind();drawCommandChart(document.getElementById("navChart"),state.contract);["reportNavChart"].forEach(id=>drawLine(document.getElementById(id),state.contract.portfolio_daily.map(r=>r.ending_nav).filter(x=>x!=null),"#19aef5",{format:"money",labels:state.contract.portfolio_daily.map(r=>r.date?.slice(5)||"")}));if(state.drawerOpen&&state.selectedStrategy)openDrawer(state.selectedStrategy,false)}
function bind(){document.querySelectorAll("[data-page]").forEach(b=>b.onclick=()=>{state.selectedPage=b.dataset.page;render()});document.querySelectorAll("[data-rail-page]").forEach(b=>b.onclick=()=>{if(!b.dataset.railPage)return;state.selectedPage=b.dataset.railPage;render()});bindMonitorControls();bindAllocationControls();document.getElementById("closeDrawer")?.addEventListener("click",()=>{state.drawerOpen=false;document.getElementById("detailDrawer").classList.remove("open")});document.getElementById("manualRefresh")?.addEventListener("click",()=>refreshOperational(true));document.querySelectorAll("[data-decision-action]").forEach(b=>b.onclick=()=>submitDecision(b.dataset.decisionAction));document.querySelectorAll("[data-contributor-id]").forEach(r=>r.onclick=()=>openDrawer(r.dataset.contributorId));bindCommandChartTooltip();rows()}
function bindMonitorControls(){document.getElementById("strategyFilter")?.addEventListener("input",e=>{state.strategyFilter=e.target.value;refresh(true)});document.getElementById("stateFilter")?.addEventListener("change",e=>{state.membershipFilter=e.target.value;refresh()});document.getElementById("familyFilter")?.addEventListener("change",e=>{state.familyFilter=e.target.value;refresh()});document.getElementById("dataFilter")?.addEventListener("change",e=>{state.dataFilter=e.target.value;refresh()});document.querySelectorAll("[data-sort]").forEach(h=>h.onclick=()=>{const key=h.dataset.sort;state.sortDir=state.sortKey===key?-state.sortDir:1;state.sortKey=key;refresh()});document.querySelectorAll("[data-view-id]").forEach(b=>b.onclick=e=>{e.stopPropagation();openDrawer(b.dataset.viewId)})}
function bindCommandChartTooltip(){const canvas=document.getElementById("navChart"),tip=document.getElementById("navChartTooltip"),detail=document.getElementById("navChartDetail"),panel=canvas?.closest(".primary-chart");if(!canvas||!detail)return;const series=commandChartSeries(state.contract),rows=series.rows,last=rows.at(-1),reset=()=>{if(last)detail.innerHTML=chartDetailMarkup({date:chartDateLabel(last.date).replace(" 0"," "),source:series.label,nav:last.ending_nav,pnl:last.net_pnl,drawdown:last.current_drawdown});tip?.classList.remove("visible");tip?.setAttribute("aria-hidden","true");canvas.removeAttribute("data-active-point")};canvas.addEventListener("mousemove",e=>{const c=state.contract,intr=c.intraday_estimate||{},hasIntr=chartShowsIntradayEstimate(c),rect=canvas.getBoundingClientRect(),ratio=(e.clientX-rect.left)/rect.width,slots=hasIntr?rows.length:Math.max(0,rows.length-1),index=Math.max(0,Math.min(slots,Math.round(ratio*slots)));canvas.dataset.activePoint=String(index);if(hasIntr&&index>=rows.length){detail.innerHTML=chartDetailMarkup({date:sessionLabel(c),source:"Delayed Estimate",nav:intr.estimated_nav,pnl:intr.estimated_pnl,drawdown:null});return}const r=rows[Math.min(index,rows.length-1)];if(r)detail.innerHTML=chartDetailMarkup({date:chartDateLabel(r.date).replace(" 0"," "),source:series.label,nav:r.ending_nav,pnl:r.net_pnl,drawdown:r.current_drawdown})});canvas.addEventListener("mouseleave",reset);canvas.addEventListener("mouseout",reset);panel?.addEventListener("mouseleave",reset);reset()}
