function openDrawer(id,resetTab=true){state.selectedStrategy=id;state.drawerOpen=true;if(resetTab)state.drawerTab="Overview";const s=selectedEntity(id),drawer=document.getElementById("detailDrawer");if(!s||!drawer)return;document.getElementById("drawerTitle").textContent=s.ui_name||s.display_name;document.getElementById("drawerSubtitle").textContent=`${s.display_id} - ${s.family} - ${s.membership_state.replaceAll("_"," ")}`;drawerContent(s);drawer.classList.add("open");drawer.setAttribute("aria-hidden","false");refresh()}
