function admissionGatePanel(s){const g=s.admission_gate;if(!g)return "";const e=g.evidence||{},checks=[["Approval record",e.approval_record],["Effective date reached",e.membership_effective_reached_in_canonical],["Signal date",!!e.canonical_signal_date],["Target rows",Number(e.canonical_target_rows)>0],["Paper fill rows",Number(e.canonical_trade_rows)>0],["Position rows",Number(e.canonical_position_rows)>0],["Verified provenance",Number(e.verified_execution_rows)>0],["Market reference price",!!e.market_reference_price_source]];return `<section class="drawer-panel narrative-panel admission-gate-panel"><header><strong>Admission Gate</strong><span>${g.status}</span></header><p>${g.exact_blocker||"All required canonical execution evidence is present."}</p><dl><dt>Combined rebalance</dt><dd>${g.combined_rebalance_allowed?"Allowed":"Blocked"}</dd><dt>Current executed</dt><dd>${g.current_executed_count}</dd><dt>Approved pending</dt><dd>${g.approved_pending_count}</dd><dt>Combined constituents</dt><dd>${g.combined_constituents}</dd></dl><div class="gate-checks">${checks.map(([label,ok])=>`<span class="${ok?"ok":"missing"}">${ok?"PASS":"MISSING"} ${label}</span>`).join("")}</div></section>`}
function drawerOverview(s){const isCombined=s.internal_id==="COMBINED_PORTFOLIO",isPending=s.current_operational_status==="PRE_OPERATIONAL"||s.membership_state==="approved_pending",statusLabel=strategyPrimaryState(s),coverage=s.price_coverage?`${s.price_coverage.priced}/${s.price_coverage.total}`:"N/A",execText=executionTypeShort(s);return `<div class="drawer-status-line">${UI.StatusBadge({label:statusLabel,tone:strategyPrimaryTone(s),dot:true})}<span>Strategy effective: <strong>${s.strategy_effective_date||"N/A"}</strong></span><span>Data State: <strong>${dataStateDisplay(s)}</strong></span></div>${isPending?`<section class="drawer-panel preop-summary"><header><strong>Pre-operational candidate</strong><span>Not admitted to the active portfolio</span></header><div class="preop-grid"><div><span>Current sleeve</span><b>N/A</b></div><div><span>Proposed sleeve</span><b>${UI.percent(s.proposed_post_admission_sleeve_weight,2)}</b></div><div><span>Operational NAV</span><b>N/A</b></div><div><span>Operational P&L</span><b>N/A</b></div><div><span>Price coverage</span><b>0/0</b></div><div><span>Paper fill</span><b>No Paper Fill</b></div><div><span>Live brokerage fill</span><b>No Live Brokerage Fill</b></div><div><span>Verified provenance</span><b>Missing verified execution provenance</b></div><div><span>Action</span><b>PENDING ADMISSION</b></div></div></section>`:`<div class="drawer-kpis"><div><span>Sleeve weight</span><strong>${UI.percent(s.sleeve_weight,2)}</strong></div><div><span>Operational NAV</span><strong>${UI.money(s.ending_nav)}</strong></div><div><span>Intraday Estimated NAV</span><strong>${UI.money(s.estimated_strategy_nav)}</strong></div><div><span>Intraday Estimated P&L</span><strong class="tone-${UI.toneForNumber(s.estimated_daily_pnl)}">${UI.money(s.estimated_daily_pnl)}</strong></div><div><span>Daily P&L</span><strong class="tone-${UI.toneForNumber(s.daily_pnl)}">${UI.money(s.daily_pnl)}</strong></div><div><span>Daily Return</span><strong class="tone-${UI.toneForNumber(s.daily_return)}">${UI.percent(s.daily_return,2)}</strong></div><div><span>Cumulative P&L</span><strong class="tone-${UI.toneForNumber(s.cumulative_pnl)}">${UI.money(s.cumulative_pnl)}</strong></div><div><span>Price Coverage</span><strong>${coverage}</strong></div><div><span>Latest Delayed Price As-Of</span><strong>${s.latest_delayed_price_as_of||"N/A"}</strong></div><div><span>Current drawdown</span><strong>${UI.percent(s.current_drawdown,2)}</strong></div><div><span>Execution Type</span><strong>${execText}</strong></div><div><span>Execution Verification</span><strong>${executionVerificationShort(s)}</strong></div><div><span>Live Fill</span><strong>${liveFillShort(s)}</strong></div></div>`}${combinedMembership(s)}${admissionGatePanel(s)}<section class="drawer-panel narrative-panel"><header><strong>Economic hypothesis</strong><span>Evidence-linked description</span></header><p>${s.hypothesis_summary||"N/A"}</p></section>${executionProvenancePanel(s)}`}
function drawerPerformance(s){const hist=drawerHistory(s),e=s.research_evidence?.research_metrics||{},rs=s.research_evidence?.research_series||{},period=s.operating_period_start&&s.operating_period_end?`${s.operating_period_start} to ${s.operating_period_end}`:"Data Pending",missing=s.research_evidence?.exact_blocker||s.research_evidence?.limitations||"ARTIFACT_GENUINELY_MISSING";return `<section class="performance-zone operational-zone"><div class="zone-title"><strong>Operational Records</strong><span>Provenance-classified records; reconstructed history is not verified Shadow-Live</span></div><div class="drawer-kpis"><div><span>Starting sleeve capital</span><strong>${UI.money(s.initial_sleeve_capital)}</strong></div><div><span>Ending NAV</span><strong>${UI.money(s.ending_nav)}</strong></div><div><span>Current drawdown</span><strong>${UI.percent(s.current_drawdown,2)}</strong></div><div><span>Max drawdown</span><strong>${UI.percent(s.max_drawdown,2)}</strong></div></div><section class="drawer-panel evidence-grid"><header><strong>Operational record</strong><span>${s.observation_count} observations | ${period}</span></header><div><span>Gross P&L</span><b>${UI.money(s.gross_pnl)}</b></div><div><span>Net P&L</span><b>${UI.money(s.net_pnl)}</b></div><div><span>Daily cost</span><b>${UI.money(s.daily_cost)}</b></div><div><span>Strategy cumulative cost</span><b>${UI.money(s.cumulative_cost)}</b></div></section>${hist.length>1?'<section class="drawer-panel chart-stack"><header><strong>Operational NAV / equity curve</strong><span>Correct 1/17 capital basis</span></header><canvas id="strategyNavChart" width="800" height="210"></canvas><header><strong>Daily P&L</strong><span>Operational record net P&L</span></header><canvas id="strategyPnlChart" width="800" height="210"></canvas><header><strong>Drawdown</strong><span>Same NAV series as current and maximum drawdown</span></header><canvas id="strategyDrawdownChart" width="800" height="210"></canvas></section>':""}</section><section class="performance-zone research-zone"><div class="zone-title"><strong>Historical Research</strong><span>Separate deployable research artifacts</span></div><section class="drawer-panel evidence-grid"><header><strong>Research evidence</strong><span>${s.research_evidence?.research_status||"Data Pending"}</span></header><div><span>Annualized return</span><b>${UI.percent(e.annualized_return,2)}</b></div><div><span>Research Sharpe</span><b>${monitorValue(e.net_sharpe)}</b></div><div><span>Annualized volatility</span><b>${UI.percent(e.annualized_volatility,2)}</b></div><div><span>Max drawdown</span><b>${UI.percent(e.max_drawdown,2)}</b></div><div><span>Win rate</span><b>${UI.percent(e.win_rate,2)}</b></div><div><span>Average daily turnover</span><b>${UI.percent(e.average_daily_turnover,2)}</b></div><div><span>Cost drag</span><b>${UI.percent(e.cost_drag,2)}</b></div><div><span>Rolling 63D Sharpe</span><b>${monitorValue(e.rolling_63d_sharpe_latest)}</b></div><div><span>Sample period</span><b>${e.sample_start||"N/A"} to ${e.sample_end||"N/A"}</b></div><div><span>Observation Count</span><b>${e.observation_count??"N/A"}</b></div><div><span>Research Decision</span><b>${e.research_decision||"N/A"}</b></div><div><span>Exact Blocker</span><b>${missing}</b></div></section>${rs.net_equity?.length>1?'<section class="drawer-panel chart-stack"><header><strong>Gross / Net research equity</strong><span>Net series shown; gross retained in contract</span></header><canvas id="researchNetChart" width="800" height="210"></canvas><header><strong>Research drawdown</strong><span>Historical research only</span></header><canvas id="researchDrawdownChart" width="800" height="210"></canvas><header><strong>Rolling 63D Sharpe</strong><span>Historical research series</span></header><canvas id="researchSharpeChart" width="800" height="210"></canvas></section>':""}</section>`}
